// These are trust anchor (self-signed) test certificates generated by the providers
// listed below for interoperability testing at IETF hackathons.

export interface IETFCertSpecialExt {
  oid: string
  label: string
  description: string
}

export interface IETFCertVector {
  id: string
  /** Maps to HybridFormatId in constants.ts */
  formatId: string
  label: string
  provider: string
  providerUrl: string
  hackathonRef: string
  algorithmOID: string
  algorithmLabel: string
  sizeBytes: number
  certType: 'composite' | 'catalyst' | 'pure-pqc' | 'chameleon'
  specialExtensions?: IETFCertSpecialExt[]
  /** DER-encoded certificate in Base64 (no line breaks) */
  derBase64: string
}

